    14→// TestFullComparisonWorkflow tests the complete comparison workflow from
    15→// data input through diffing to all output formats.
    16→func TestFullComparisonWorkflow(t *testing.T) {
    17→	// Create test data
    18→	sourceData := &export.Data{
    19→		Blueprints: []api.Blueprint{
    20→			{"identifier": "service", "title": "Service", "schema": map[string]interface{}{}},
    21→			{"identifier": "old-bp", "title": "Old Blueprint"},
    22→		},
    23→		Actions: []api.Action{
    24→			{"identifier": "deploy", "title": "Deploy"},
    25→		},
    26→	}
    27→
    28→	targetData := &export.Data{
    29→		Blueprints: []api.Blueprint{
    30→			{"identifier": "service", "title": "Service Updated", "schema": map[string]interface{}{}},
    31→			{"identifier": "new-bp", "title": "New Blueprint"},
    32→		},
    33→		Actions: []api.Action{
    34→			{"identifier": "deploy", "title": "Deploy"},
    35→		},
    36→	}
    37→
    38→	// Run diff
    39→	differ := NewDiffer()
    40→	result := differ.Diff(sourceData, targetData)
    41→	result.Source = "source-org"
    42→	result.Target = "target-org"
    43→	result.Timestamp = "2026-02-05T19:30:00Z"
    44→
    45→	// Verify results
    46→	if result.Identical {
    47→		t.Error("expected differences, got identical")
    48→	}
    49→
    50→	if result.Blueprints.Summary.Added != 1 {
    51→		t.Errorf("expected 1 added blueprint, got %d", result.Blueprints.Summary.Added)
    52→	}
    53→	if result.Blueprints.Summary.Modified != 1 {
    54→		t.Errorf("expected 1 modified blueprint, got %d", result.Blueprints.Summary.Modified)
    55→	}
    56→	if result.Blueprints.Summary.Removed != 1 {
    57→		t.Errorf("expected 1 removed blueprint, got %d", result.Blueprints.Summary.Removed)
    58→	}
    59→
    60→	// Test text output
    61→	var textBuf bytes.Buffer
    62→	textFormatter := NewTextFormatter(&textBuf, false, false)
    63→	if err := textFormatter.Format(result); err != nil {
    64→		t.Fatalf("text formatter error: %v", err)
    65→	}
    66→	if textBuf.Len() == 0 {
    67→		t.Error("expected text output, got empty")
    68→	}
    69→
    70→	// Test JSON output
    71→	var jsonBuf bytes.Buffer
    72→	jsonFormatter := NewJSONFormatter(&jsonBuf)
    73→	if err := jsonFormatter.Format(result); err != nil {
    74→		t.Fatalf("json formatter error: %v", err)
    75→	}
    76→	if jsonBuf.Len() == 0 {
    77→		t.Error("expected JSON output, got empty")
    78→	}
    79→
    80→	// Test HTML output
    81→	var htmlBuf bytes.Buffer
    82→	htmlFormatter := NewHTMLFormatter(&htmlBuf, false)
    83→	if err := htmlFormatter.Format(result); err != nil {
    84→		t.Fatalf("html formatter error: %v", err)
    85→	}
    86→	if htmlBuf.Len() == 0 {
    87→		t.Error("expected HTML output, got empty")
    88→	}
    89→}
