    91→// TestIdenticalOrganizations tests comparing two identical organizations.
    92→func TestIdenticalOrganizations(t *testing.T) {
    93→	data := &export.Data{
    94→		Blueprints: []api.Blueprint{
    95→			{"identifier": "service", "title": "Service"},
    96→		},
    97→		Actions: []api.Action{
    98→			{"identifier": "deploy", "title": "Deploy"},
    99→		},
   100→		Scorecards: []api.Scorecard{
   101→			{"identifier": "quality", "title": "Quality"},
   102→		},
   103→	}
   104→
   105→	differ := NewDiffer()
   106→	result := differ.Diff(data, data)
   107→
   108→	if !result.Identical {
   109→		t.Error("expected identical, got differences")
   110→	}
   111→
   112→	// All summaries should be zero
   113→	if result.Blueprints.Summary.Added != 0 ||
   114→		result.Blueprints.Summary.Modified != 0 ||
   115→		result.Blueprints.Summary.Removed != 0 {
   116→		t.Error("expected zero blueprint changes for identical data")
   117→	}
   118→	if result.Actions.Summary.Added != 0 ||
   119→		result.Actions.Summary.Modified != 0 ||
   120→		result.Actions.Summary.Removed != 0 {
   121→		t.Error("expected zero action changes for identical data")
   122→	}
   123→}
