   384→// TestFieldLevelDiffs tests detailed field-level difference detection.
   385→func TestFieldLevelDiffs(t *testing.T) {
   386→	sourceData := &export.Data{
   387→		Blueprints: []api.Blueprint{
   388→			{
   389→				"identifier":  "bp1",
   390→				"title":       "Original Title",
   391→				"description": "Original Description",
   392→				"schema": map[string]interface{}{
   393→					"properties": map[string]interface{}{
   394→						"name": map[string]interface{}{
   395→							"type": "string",
   396→						},
   397→					},
   398→				},
   399→			},
   400→		},
   401→	}
   402→
   403→	targetData := &export.Data{
   404→		Blueprints: []api.Blueprint{
   405→			{
   406→				"identifier":  "bp1",
   407→				"title":       "Updated Title",
   408→				"description": "Original Description",
   409→				"schema": map[string]interface{}{
   410→					"properties": map[string]interface{}{
   411→						"name": map[string]interface{}{
   412→							"type": "number",
   413→						},
   414→					},
   415→				},
   416→			},
   417→		},
   418→	}
   419→
   420→	differ := NewDiffer()
   421→	result := differ.Diff(sourceData, targetData)
   422→
   423→	if result.Blueprints.Summary.Modified != 1 {
   424→		t.Fatalf("expected 1 modified blueprint, got %d", result.Blueprints.Summary.Modified)
   425→	}
   426→
   427→	modified := result.Blueprints.Modified[0]
   428→	if modified.Identifier != "bp1" {
   429→		t.Errorf("expected modified identifier 'bp1', got %s", modified.Identifier)
   430→	}
   431→
   432→	// Should have field diffs for title and nested schema property
   433→	if len(modified.FieldDiffs) < 2 {
   434→		t.Errorf("expected at least 2 field diffs, got %d", len(modified.FieldDiffs))
   435→	}
   436→
   437→	// Check for title diff
   438→	foundTitle := false
   439→	foundSchema := false
   440→	for _, fd := range modified.FieldDiffs {
   441→		if fd.Path == "title" {
   442→			foundTitle = true
   443→			if fd.SourceValue != "Original Title" || fd.TargetValue != "Updated Title" {
   444→				t.Errorf("title diff values incorrect: source=%v target=%v",
   445→					fd.SourceValue, fd.TargetValue)
   446→			}
   447→		}
   448→		if strings.Contains(fd.Path, "schema.properties.name.type") {
   449→			foundSchema = true
   450→			if fd.SourceValue != "string" || fd.TargetValue != "number" {
   451→				t.Errorf("schema diff values incorrect: source=%v target=%v",
   452→					fd.SourceValue, fd.TargetValue)
   453→			}
   454→		}
   455→	}
   456→
   457→	if !foundTitle {
   458→		t.Error("missing title field diff")
   459→	}
   460→	if !foundSchema {
   461→		t.Error("missing schema field diff")
   462→	}
   463→}
