   505→// TestLargeDataset tests comparison with larger datasets.
   506→func TestLargeDataset(t *testing.T) {
   507→	// Create source with 100 blueprints
   508→	var sourceBlueprints []api.Blueprint
   509→	for i := 0; i < 100; i++ {
   510→		sourceBlueprints = append(sourceBlueprints, api.Blueprint{
   511→			"identifier": string(rune('a'+i/26)) + string(rune('a'+i%26)),
   512→			"title":      "Blueprint " + string(rune('A'+i/26)) + string(rune('A'+i%26)),
   513→		})
   514→	}
   515→
   516→	// Create target with 100 blueprints, 50 same, 25 modified, 25 new (25 removed from source)
   517→	var targetBlueprints []api.Blueprint
   518→	for i := 0; i < 50; i++ {
   519→		// Same as source
   520→		targetBlueprints = append(targetBlueprints, api.Blueprint{
   521→			"identifier": string(rune('a'+i/26)) + string(rune('a'+i%26)),
   522→			"title":      "Blueprint " + string(rune('A'+i/26)) + string(rune('A'+i%26)),
   523→		})
   524→	}
   525→	for i := 50; i < 75; i++ {
   526→		// Modified
   527→		targetBlueprints = append(targetBlueprints, api.Blueprint{
   528→			"identifier": string(rune('a'+i/26)) + string(rune('a'+i%26)),
   529→			"title":      "Modified Blueprint " + string(rune('A'+i/26)) + string(rune('A'+i%26)),
   530→		})
   531→	}
   532→	for i := 100; i < 125; i++ {
   533→		// New
   534→		targetBlueprints = append(targetBlueprints, api.Blueprint{
   535→			"identifier": "new-" + string(rune('a'+i/26)) + string(rune('a'+i%26)),
   536→			"title":      "New Blueprint " + string(rune('A'+i/26)) + string(rune('A'+i%26)),
   537→		})
   538→	}
   539→
   540→	sourceData := &export.Data{Blueprints: sourceBlueprints}
   541→	targetData := &export.Data{Blueprints: targetBlueprints}
   542→
   543→	differ := NewDiffer()
   544→	result := differ.Diff(sourceData, targetData)
   545→
   546→	if result.Identical {
   547→		t.Error("expected differences")
   548→	}
   549→
   550→	// 25 removed (indices 75-99 from source)
   551→	if result.Blueprints.Summary.Removed != 25 {
   552→		t.Errorf("expected 25 removed, got %d", result.Blueprints.Summary.Removed)
   553→	}
   554→
   555→	// 25 modified
   556→	if result.Blueprints.Summary.Modified != 25 {
   557→		t.Errorf("expected 25 modified, got %d", result.Blueprints.Summary.Modified)
   558→	}
   559→
   560→	// 25 added
   561→	if result.Blueprints.Summary.Added != 25 {
   562→		t.Errorf("expected 25 added, got %d", result.Blueprints.Summary.Added)
   563→	}
   564→}
