     1→package config
     2→
     3→import (
     4→	"fmt"
     5→	"os"
     6→	"path/filepath"
     7→
     8→	"github.com/joho/godotenv"
     9→	"gopkg.in/yaml.v3"
    10→)
    11→
    12→// ConfigManager manages configuration loading with precedence: CLI flags > env vars > config file.
    13→type ConfigManager struct {
    14→	configPath string
    15→}
    16→
    17→// ConfigPath returns the configuration file path.
    18→func (cm *ConfigManager) ConfigPath() string {
    19→	return cm.configPath
    20→}
    21→
    22→// NewConfigManager creates a new ConfigManager.
    23→func NewConfigManager(configPath string) *ConfigManager {
    24→	if configPath == "" {
    25→		configPath = DefaultConfigPath()
    26→	}
    27→
    28→	// Load .env files (doesn't override existing env vars)
    29→	loadEnvFiles()
    30→
    31→	return &ConfigManager{
    32→		configPath: configPath,
    33→	}
    34→}
    35→
    36→// loadEnvFiles loads .env files from current directory and ~/.port/.env.
    37→func loadEnvFiles() {
    38→	// Skip .env loading during tests
    39→	if os.Getenv("TESTING") != "" {
    40→		return
    41→	}
    42→
    43→	// Try current directory
    44→	if _, err := os.Stat(".env"); err == nil {
    45→		godotenv.Load(".env")
    46→	}
    47→
    48→	// Try ~/.port/.env
    49→	home, err := os.UserHomeDir()
    50→	if err == nil {
    51→		envPath := filepath.Join(home, ".port", ".env")
    52→		if _, err := os.Stat(envPath); err == nil {
    53→			godotenv.Load(envPath)
    54→		}
    55→	}
    56→}
    57→
    58→// Load loads configuration with precedence: env vars > config file > defaults.
    59→func (cm *ConfigManager) Load() (*Config, error) {
    60→	// Start with defaults
    61→	cfg := &Config{
    62→		DefaultOrg:    "",
    63→		Organizations: make(map[string]OrganizationConfig),
    64→		Backend: BackendConfig{
    65→			URL:     "http://localhost:8080",
    66→			Timeout: 300,
    67→		},
    68→	}
    69→
    70→	// Load from file if exists
    71→	if _, err := os.Stat(cm.configPath); err == nil {
    72→		if err := cm.loadFromFile(cfg); err != nil {
    73→			return nil, fmt.Errorf("failed to load config file: %w", err)
    74→		}
    75→	}
    76→
    77→	// Override with environment variables
    78→	cm.loadFromEnv(cfg)
    79→
    80→	return cfg, nil
    81→}
