   126→// resolveOrgConfig resolves organization config with CLI/env overrides.
   127→func (cm *ConfigManager) resolveOrgConfig(cfg *Config, clientID, clientSecret, apiURL, orgName, orgType string) (*OrganizationConfig, error) {
   128→	// Check environment variables if CLI flags not provided
   129→	if clientID == "" {
   130→		if orgType == "target" {
   131→			clientID = os.Getenv("PORT_TARGET_CLIENT_ID")
   132→		} else {
   133→			clientID = os.Getenv("PORT_CLIENT_ID")
   134→		}
   135→	}
   136→	if clientSecret == "" {
   137→		if orgType == "target" {
   138→			clientSecret = os.Getenv("PORT_TARGET_CLIENT_SECRET")
   139→		} else {
   140→			clientSecret = os.Getenv("PORT_CLIENT_SECRET")
   141→		}
   142→	}
   143→	if apiURL == "" {
   144→		if orgType == "target" {
   145→			apiURL = os.Getenv("PORT_TARGET_API_URL")
   146→		} else {
   147→			apiURL = os.Getenv("PORT_API_URL")
   148→		}
   149→		if apiURL == "" {
   150→			apiURL = "https://api.getport.io/v1"
   151→		}
   152→	}
   153→
   154→	// If no CLI/env overrides and no org name specified, return nil to allow fallback
   155→	if clientID == "" && clientSecret == "" && apiURL == "" && orgName == "" {
   156→		return nil, nil
   157→	}
   158→
   159→	// Apply CLI/env overrides if provided
   160→	if clientID != "" || clientSecret != "" || apiURL != "" {
   161→		overrideOrg := orgName
   162→		if overrideOrg == "" {
   163→			overrideOrg = cfg.DefaultOrg
   164→		}
   165→		if overrideOrg == "" {
   166→			overrideOrg = fmt.Sprintf("cli-override-%s", orgType)
   167→		}
   168→
   169→		// Get existing org config if it exists
   170→		existingOrg, exists := cfg.Organizations[overrideOrg]
   171→
   172→		// Build override config
   173→		overrideConfig := OrganizationConfig{
   174→			ClientID:     clientID,
   175→			ClientSecret: clientSecret,
   176→			APIURL:       apiURL,
   177→		}
   178→
   179→		// Fill in missing values from existing config or defaults
   180→		if overrideConfig.ClientID == "" {
   181→			if exists {
   182→				overrideConfig.ClientID = existingOrg.ClientID
   183→			} else {
   184→				return nil, fmt.Errorf(`missing credentials for %s org
   185→
   186→To authenticate, provide credentials using one of these methods:
   187→
   188→1. CLI flags (recommended for standalone binaries):
   189→   port export --client-id YOUR_CLIENT_ID --client-secret YOUR_CLIENT_SECRET
   190→   port import --target-client-id YOUR_CLIENT_ID --target-client-secret YOUR_CLIENT_SECRET
   191→
   192→2. Environment variables:
   193→   export PORT_CLIENT_ID="your-client-id"
   194→   export PORT_CLIENT_SECRET="your-client-secret"
   195→   export PORT_TARGET_CLIENT_ID="your-target-client-id"
   196→   export PORT_TARGET_CLIENT_SECRET="your-target-client-secret"
   197→
   198→3. Configuration file:
   199→   Run: port config --init
   200→   Then edit: %s`, orgType, cm.configPath)
   201→			}
   202→		}
   203→		if overrideConfig.ClientSecret == "" {
   204→			if exists {
   205→				overrideConfig.ClientSecret = existingOrg.ClientSecret
   206→			} else {
   207→				return nil, fmt.Errorf(`missing credentials for %s org
   208→
   209→To authenticate, provide credentials using one of these methods:
   210→
   211→1. CLI flags (recommended for standalone binaries):
   212→   port export --client-id YOUR_CLIENT_ID --client-secret YOUR_CLIENT_SECRET
   213→   port import --target-client-id YOUR_CLIENT_ID --target-client-secret YOUR_CLIENT_SECRET
   214→
   215→2. Environment variables:
   216→   export PORT_CLIENT_ID="your-client-id"
   217→   export PORT_CLIENT_SECRET="your-client-secret"
   218→   export PORT_TARGET_CLIENT_ID="your-target-client-id"
   219→   export PORT_TARGET_CLIENT_SECRET="your-target-client-secret"
   220→
   221→3. Configuration file:
   222→   Run: port config --init
   223→   Then edit: %s`, orgType, cm.configPath)
   224→			}
   225→		}
   226→		if overrideConfig.APIURL == "" {
   227→			if exists {
   228→				overrideConfig.APIURL = existingOrg.APIURL
   229→			} else {
   230→				overrideConfig.APIURL = "https://api.getport.io/v1"
   231→			}
   232→		}
   233→
   234→		cfg.Organizations[overrideOrg] = overrideConfig
   235→		if orgType == "base" {
   236→			cfg.DefaultOrg = overrideOrg
   237→		}
   238→	}
   239→
   240→	return cfg.GetOrgConfig(orgName)
   241→}
